// ToInstanceData converts an Instance to its JSON-serialisable form for persistence.
// UpdatedAt is always refreshed to the current time.
func (i *Instance) ToInstanceData() InstanceData {
	data := InstanceData{
		Title:                  i.Title,
		Path:                   i.Path,
		Branch:                 i.Branch,
		Status:                 i.Status,
